import { mergeProps, useRender } from "@base-ui/react";
import * as stylex from "@stylexjs/stylex";
import type { _BaseDivProps, PropsWithStylex } from "@/utils/stylex.utils";
import { Surface, type SurfaceProps } from "../Surface/surface";
import {
	cardPaddingStyles,
	cardSectionStyles,
	cardTextStyles,
} from "./card.styles";

type CardProps = SurfaceProps;

type SectionPadding = keyof typeof cardPaddingStyles;

type CardSectionProps = _BaseDivProps & {
	padding?: SectionPadding;
};
function Card(props: CardProps) {
	return <Surface padding="medium" withBorder variant="sunken" {...props} />;
}
function CardHeader({
	render,
	padding = "medium",
	style,
	...props
}: CardSectionProps) {
	const stylexProps = stylex.props(
		cardSectionStyles.base,
		cardSectionStyles.header,
		cardPaddingStyles[padding],
		style,
	);
	const mergedProps = mergeProps(stylexProps, props);
	return useRender({
		defaultTagName: "div",
		props: mergedProps,
		render,
	});
}

function CardBody({
	render,
	padding = "medium",
	style,
	...props
}: CardSectionProps) {
	const stylexProps = stylex.props(
		cardSectionStyles.base,
		cardSectionStyles.body,
		cardPaddingStyles[padding],
		style,
	);
	const mergedProps = mergeProps(stylexProps, props);
	return useRender({
		defaultTagName: "div",
		props: mergedProps,
		render,
	});
}

function CardFooter({
	render,
	padding = "medium",
	style,
	...props
}: CardSectionProps) {
	const stylexProps = stylex.props(
		cardSectionStyles.base,
		cardSectionStyles.footer,
		cardPaddingStyles[padding],
		style,
	);
	const mergedProps = mergeProps(stylexProps, props);
	return useRender({
		defaultTagName: "div",
		props: mergedProps,
		render,
	});
}

type CardTitleProps = PropsWithStylex<useRender.ComponentProps<"h1">>;

function CardTitle({ render, style, ...props }: CardTitleProps) {
	const stylexProps = stylex.props(cardTextStyles.title, style);
	const mergedProps = mergeProps(stylexProps, props);
	return useRender({
		defaultTagName: "div",
		props: mergedProps,
		render,
	});
}

type CardDescriptionProps = PropsWithStylex<useRender.ComponentProps<"p">>;

function CardDescription({ render, style, ...props }: CardDescriptionProps) {
	const stylexProps = stylex.props(cardTextStyles.description, style);
	const mergedProps = mergeProps(stylexProps, props);
	return useRender({
		defaultTagName: "div",
		props: mergedProps,
		render,
	});
}
export type {
	CardProps,
	CardDescriptionProps,
	CardSectionProps,
	CardTitleProps,
};
export { Card, CardDescription, CardTitle, CardFooter, CardBody, CardHeader };

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import { fontSize, fontWeight, spacing } from "@/lib/theme/tokens.stylex";

export const cardStyles = stylex.create({
	base: {
		backgroundColor: theme.surface,
		borderWidth: 1,
		borderStyle: "solid",
		borderColor: theme.border,
		borderRadius: theme.borderRadius,
		boxSizing: "border-box",
	},
});

export const cardPaddingStyles = stylex.create({
	small: { padding: spacing.small },
	medium: { padding: spacing.medium },
	large: { padding: spacing.large },
});

export const cardSectionStyles = stylex.create({
	base: {
		boxSizing: "border-box",
	},
	header: {
		borderBottomWidth: 1,
		borderBottomStyle: "solid",
		borderBottomColor: theme.borderSubtle,
	},
	body: {
		opacity: 1,
	},
	footer: {
		borderTopWidth: 1,
		borderTopStyle: "solid",
		borderTopColor: theme.borderSubtle,
	},
});

export const cardTextStyles = stylex.create({
	title: {
		margin: 0,
		color: theme.contentPrimary,
		fontSize: fontSize.medium,
		fontWeight: fontWeight.semibold,
		lineHeight: 1.3,
	},
	description: {
		margin: 0,
		color: theme.contentSecondary,
		fontSize: fontSize.small,
		lineHeight: 1.5,
	},
});
